from urllib.parse import urlparse, urlunparse

def get_target_for_redirect(target: str, domain: str) -> str:
    parsed = urlparse(target)
    hostname = parsed.hostname
    if hostname is None:
        return f'https://{domain}'
    if hostname == domain or hostname.endswith('.' + domain):
        # Ensure https scheme
        new_parsed = parsed._replace(scheme='https')
        return urlunparse(new_parsed)
    return f'https://{domain}'

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Resolve both paths to absolute, normalized paths
        abs_dir = os.path.abspath(dir_path)
        abs_file = os.path.abspath(os.path.join(abs_dir, filename))
        # Ensure the file is inside the directory
        if os.path.commonpath([abs_dir, abs_file]) != abs_dir:
            return ""
        with open(abs_file, 'r', encoding='utf-8') as f:
            return f.read()
    except Exception:
        return ""

import tarfile
import os

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        dest_real = os.path.realpath(dest_path)
        with tarfile.open(tar_path, 'r') as tar:
            # Validate all members before extraction
            for member in tar.getmembers():
                # Compute the intended extraction path for this member
                member_path = os.path.join(dest_path, member.name)
                if member.issym():
                    # Symlink: check where the link points
                    linkname = member.linkname
                    if os.path.isabs(linkname):
                        target = linkname
                    else:
                        symlink_dir = os.path.dirname(member_path)
                        target = os.path.normpath(os.path.join(symlink_dir, linkname))
                    target_real = os.path.realpath(target)
                    if not (target_real.startswith(dest_real + os.sep) or target_real == dest_real):
                        return False
                elif member.islnk():
                    # Hard link: target is another file in the archive
                    target_path = os.path.join(dest_path, member.linkname)
                    target_real = os.path.realpath(target_path)
                    if not (target_real.startswith(dest_real + os.sep) or target_real == dest_real):
                        return False
                else:
                    # Regular file, directory, etc.
                    member_real = os.path.realpath(member_path)
                    if not (member_real.startswith(dest_real + os.sep) or member_real == dest_real):
                        return False
            # All members are safe, extract
            tar.extractall(dest_path)
            return True
    except Exception:
        return False

