import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    try:
        tree = ast.parse(expr, mode='eval')
    except Exception:
        return ""

    allowed_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op = allowed_ops[type(node.op)]
            return op(left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op = allowed_ops[type(node.op)]
            return op(operand)
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.Num):  # Python < 3.8
            return node.n
        else:
            raise ValueError("Unsupported expression")

    try:
        result = _eval(tree)
        return str(result)
    except Exception:
        return ""

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    # Mapping of valid info types to header keys
    type_to_key = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }

    # Validate info_type
    if info_type not in type_to_key:
        return header

    # Validate info_content: must be a string and not contain CR or LF
    if not isinstance(info_content, str):
        return header
    if '\r' in info_content or '\n' in info_content:
        return header

    # Create a copy of the header to avoid mutating the original
    updated_header = header.copy()
    updated_header[type_to_key[info_type]] = info_content
    return updated_header

