import _pickle as cPickle
import base64


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    try:
        # Get the AuthToken from headers
        token_b64 = headers.get('AuthToken')
        if not token_b64:
            return None

        # Decode from base64
        token_bytes = base64.b64decode(token_b64)

        # Deserialize with cPickle
        token = cPickle.loads(token_bytes)

        # Check if token is valid
        if hasattr(token, 'is_valid') and callable(token.is_valid):
            if not token.is_valid():
                return None
        elif hasattr(token, 'valid'):
            if not token.valid:
                return None
        else:
            # If no validity check available, assume invalid
            return None

        # Return the data in token object
        return token

    except Exception:
        return None

